var e=JSON.parse(`[{"id":"L2_1","type":"dialog","speaker":"LEESOOYEON_COFFIN_NULL_NULL","text":{"KOREA":"어떤가요, 스승님? 뭔가 찾으셨습니까?","JPN":"どうですか、師匠？　何か見つかりましたか？","ENG":"Well, Master? Have you found anything?","TWN":"怎麼樣了，師父？有發現什麼嗎？"},"stage":{"bg":"COUNTERSIDE_NORMAL","slots":{"L":null,"C":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L5_1","type":"dialog","speaker":"HILDE_FENRIR_NULL_NULL","text":{"KOREA":"아니. 아직까지는 별다른 게 없군.","JPN":"いや。今のところ何もないな。","ENG":"Negative. Nothing special yet.","TWN":"沒有，暫時沒發現。"},"stage":{"bg":"COUNTERSIDE_NORMAL","slots":{"L":{"char_id":"HILDE_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L6_1","type":"dialog","speaker":"HILDE_FENRIR_NULL_NULL","text":{"KOREA":"놈이 있다는 좌표가 이곳이 확실한가?","JPN":"奴がいる座標はここで間違いないのか？","ENG":"Are you sure the target is at these coordinates?","TWN":"那個傢伙的座標確定是這裡嗎？"},"stage":{"bg":"COUNTERSIDE_NORMAL","slots":{"L":{"char_id":"HILDE_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L8_1","type":"dialog","speaker":"LEESOOYEON_COFFIN_NULL_NULL","text":{"KOREA":"틀림없습니다. 몇 번이고 확인했으니까요.","JPN":"間違いありません。何度も確認しています。","ENG":"A hundred percent. I double, triple checked them.","TWN":"沒錯，我已經確認好幾次了。"},"stage":{"bg":"COUNTERSIDE_NORMAL","slots":{"L":null,"C":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L9_1","type":"dialog","speaker":"LEESOOYEON_COFFIN_NULL_NULL","text":{"KOREA":"작전 지역에서 포착된 차원 이동의 궤적은 해당 좌표로 향한 게 분명합니다.","JPN":"作戦地域で捕捉された次元移動の軌跡によると、該当座標に向かったことは明らかです。","ENG":"The traces of the dimensional jump from the AO leads right to those coordinates.","TWN":"在作戰地區捕獲的次元移動軌跡確實指向這個座標。"},"stage":{"bg":"COUNTERSIDE_NORMAL","slots":{"L":null,"C":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L10_1","type":"dialog","speaker":"LEESOOYEON_COFFIN_NULL_NULL","text":{"KOREA":"상처를 입은 상태라면 아직 그 일대에 숨어 있겠죠.","JPN":"負傷している状態なら、まだその一帯に隠れているでしょう。","ENG":"If our target has been wounded, that's where she must be hiding.","TWN":"如果是受了傷的話，一定還藏在那附近。"},"stage":{"bg":"COUNTERSIDE_NORMAL","slots":{"L":null,"C":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L11_1","type":"dialog","speaker":"LEESOOYEON_COFFIN_NULL_NULL","text":{"KOREA":"......","JPN":"……","ENG":"......","TWN":"……"},"stage":{"bg":"COUNTERSIDE_NORMAL","slots":{"L":null,"C":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L12_1","type":"dialog","speaker":"LEESOOYEON_COFFIN_NULL_NULL","text":{"KOREA":"하지만 스승님, 굳이 직접 이면세계로 다이브해서까지 찾아야 될 필요가 있을까요?","JPN":"しかし師匠、わざわざ裏世界にダイブして探す必要はあるのでしょうか？","ENG":"But Master, do we really need to bother diving for her?","TWN":"但是師父…有必要躍入到異界尋找嗎？"},"stage":{"bg":"COUNTERSIDE_NORMAL","slots":{"L":null,"C":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L13_1","type":"dialog","speaker":"LEESOOYEON_COFFIN_NULL_NULL","text":{"KOREA":"이러지 않아도 놈이 다시 나타나면 관리국이 먼저 연락해 올 겁니다.","JPN":"こんなことしなくても、また奴が現れたら管理局から連絡が来ると思います。","ENG":"I'm sure the Administration will reach out first if she pops back up.","TWN":"就算我們不找，等它再次出現的時候管理局也會通知我們的。"},"stage":{"bg":"COUNTERSIDE_NORMAL","slots":{"L":null,"C":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L16_1","type":"dialog","speaker":"HILDE_FENRIR_NULL_NULL","text":{"KOREA":"......","JPN":"……","ENG":"......","TWN":"……"},"stage":{"bg":"COUNTERSIDE_NORMAL","slots":{"L":{"char_id":"HILDE_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L17_1","type":"dialog","speaker":"LEESOOYEON_COFFIN_NULL_NULL","text":{"KOREA":"애초에 미나 양이 네르비에를 격파했다는 것부터 단순한 착각일 수도 있습니다.","JPN":"そもそもミナさんがネルヴィエを撃破したということが、単なる勘違いかもしれません。","ENG":"After all, Mina may have only thought she defeated Nervier.","TWN":"當時米娜消滅尼爾比耶一事可能是我們弄錯了。"},"stage":{"bg":"COUNTERSIDE_NORMAL","slots":{"L":{"char_id":"HILDE_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L18_1","type":"dialog","speaker":"LEESOOYEON_COFFIN_NULL_NULL","text":{"KOREA":"전투 중에 도주한 적을 격파했다고 여기는 일은 흔하니까요.","JPN":"戦闘中に逃走した敵を撃破したと勘違いすることはよくあります。","ENG":"It's not uncommon for Counters to mistakenly believe they've killed an opponent who actually fled alive.","TWN":"在戰鬥中誤將逃走的敵人認為將其消滅掉的事情也曾有發生過不是嗎。"},"stage":{"bg":"COUNTERSIDE_NORMAL","slots":{"L":{"char_id":"HILDE_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L19_1","type":"dialog","speaker":"LEESOOYEON_COFFIN_NULL_NULL","text":{"KOREA":"미나 양은 아직 미숙한 편이고 하니 충분히 그럴 수 있겠죠.","JPN":"ミナさんはまだ未熟ですし、その可能性も十分あります。","ENG":"Given how Mina's still relatively inexperienced, that's not impossible.","TWN":"米娜畢竟還是新人，所以的確極有有可能。"},"stage":{"bg":"COUNTERSIDE_NORMAL","slots":{"L":{"char_id":"HILDE_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L20_1","type":"dialog","speaker":"HILDE_FENRIR_NULL_NULL","text":{"KOREA":"그 자리에 주시윤도 있었다고 들었는데, 아닌가?","JPN":"その場にアキヤマもいたと聞いたが、違うか？","ENG":"But wasn't Shiyoon present at the time as well?","TWN":"聽說當時周時雲也在場，難道不是？"},"stage":{"bg":"COUNTERSIDE_NORMAL","slots":{"L":{"char_id":"HILDE_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L21_1","type":"dialog","speaker":"LEESOOYEON_COFFIN_NULL_NULL","text":{"KOREA":"......맞습니다.","JPN":"……はい。","ENG":"Yes... He was.","TWN":"……是在場。"},"stage":{"bg":"COUNTERSIDE_NORMAL","slots":{"L":{"char_id":"HILDE_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_HATE"}}}},{"id":"L22_1","type":"dialog","speaker":"HILDE_FENRIR_NULL_NULL","text":{"KOREA":"신입이라면 몰라도 그 녀석까지 잘못 알았을 리 없어.","JPN":"新人ならまだしも、あいつまで勘違いするはずがない。","ENG":"I can see the rookie making that mistake, but not Shiyoon.","TWN":"新人可能會，但他絕對不會判斷錯的。"},"stage":{"bg":"COUNTERSIDE_NORMAL","slots":{"L":{"char_id":"HILDE_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_HATE"}}}},{"id":"L23_1","type":"dialog","speaker":"HILDE_FENRIR_NULL_NULL","text":{"KOREA":"나도 아니라고 믿고 싶지만...... 이번엔 느낌이 좋지 않아.","JPN":"私も違うと信じたいところだが……今回は悪い予感がする。","ENG":"As much as I want to believe otherwise... I've got a bad feeling about this.","TWN":"我雖然也不想相信……但這次預感很不好。"},"stage":{"bg":"COUNTERSIDE_NORMAL","slots":{"L":{"char_id":"HILDE_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_HATE"}}}},{"id":"L24_1","type":"dialog","speaker":"LEESOOYEON_COFFIN_NULL_NULL","text":{"KOREA":"......","JPN":"……","ENG":"......","TWN":"……"},"stage":{"bg":"COUNTERSIDE_NORMAL","slots":{"L":{"char_id":"HILDE_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L25_1","type":"dialog","speaker":"HILDE_FENRIR_NULL_NULL","text":{"KOREA":"굳이 마음에 걸리는 일을 남겨 둘 필요는 없지.","JPN":"あえて気がかりのまま放って置く必要もない。","ENG":"There's no reason to go on feeling anxious about something you can fix yourself.","TWN":"所以，我一定要弄清楚。"},"stage":{"bg":"COUNTERSIDE_NORMAL","slots":{"L":{"char_id":"HILDE_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L26_1","type":"dialog","speaker":"HILDE_FENRIR_NULL_NULL","text":{"KOREA":"진실이 어떻든 상관없어. 놈을 찾아서 없애 버리면 끝날 일이다. ","JPN":"真実がどうであろうと関係ない。奴を見つけて始末してしまえば済む話だ。","ENG":"It doesn't matter what really happened. All I need to do is find her and take her out. ","TWN":"不管真相如何，只要找到那個傢伙解決掉就可以了。"},"stage":{"bg":"COUNTERSIDE_NORMAL","slots":{"L":{"char_id":"HILDE_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_IDLE"}}}}]`);export{e as default};